//playback of a standard MIDI file stashed in RAM in a huge memory block accessed by a handle// June 2026#include "stdio.h"#include "Events.h"#include "muMIDIPlayer.h"#include "muTimer.h"#include "openmidfilemac.h"#define PBLOCKPOOL 3Handle processedEvents; //processed events go hereunsigned long masterCount; //total of events in the preprocessed structunsigned long masterParser; //used to parse the preprocessed structunsigned long absUs=0L; //used to stash absolute microsec for storing events into one structunsigned long *trackStarters; //holds the start of each trackunsigned long *trackParsers; //holds the offsets from the start of each trackunsigned long *pendingDeltas; //holds the next time delta for each track, in ticksunsigned char *oldCmds; //to keep track of old command during run-on commandsstatic ParamBlockRec pbPool[PBLOCKPOOL]; //since PBWrite is done async, round robin several of them to avoid overwriting an unfinished onestatic int pbPoolIdx = 0; //round robin index for the PBWrite block param poolint tracksFinished;  //tick this by 1 when a 0xFF 0x2F 0x00 End of Track is reachedBoolean *trackDone; //mark as done, so we don't waste time with them//midiPanic: shuts all channels and resets midi devicevoid allNotesOff(){unsigned char shut[3];unsigned char i=0;for(i=0; i<16; i++)	{		shut[0] = 0xB0 | i;	shut[1] = 0x79; //reset all controllers	shut[2] = 0x00;	syncSendMidiEvent(3, shut);		shut[1] = 0x7b; //all notes off command	syncSendMidiEvent(3, shut);		shut[0] = 0xE0 | i;	shut[1] = 0x00; //reset all controllers	shut[2] = 0x40; //reset all controllers	syncSendMidiEvent(3, shut);	}Delay(60,nil);}int pressSpacePause(void){EventRecord evt;Boolean wutup;char c;for(;;) {	wutup = GetNextEvent(everyEvent, &evt);	if(wutup && evt.what == keyDown)		{		c = evt.message & charCodeMask;		if(c == ' ') //space			return 0;		if(c == 'q') return 1;		}	}}//sendMidiEvent Round Robin style with ParamBlocks, useful for async calls to avoid overwriting a paramblock before the last one is donevoid sendMidiEventRR(short byteCount, unsigned char *msgToSend)	{	ParamBlockRec *pB = &(pbPool[pbPoolIdx]);			pB->ioParam.ioRefNum = myParamBlock.ioParam.ioRefNum; //could be done at init time once only!	pB->ioParam.ioReqCount = byteCount;	pB->ioParam.ioBuffer = (char *)msgToSend; //should we use unsigned char*?	PBWrite(pB, true);			pbPoolIdx = (pbPoolIdx+1) % PBLOCKPOOL;		}//the actual sending of bytes to the serial port, containing proper MIDI spec commandsvoid sendMidiEvent(short byteCount, unsigned char *msgToSend)	{	myParamBlock.ioParam.ioReqCount = byteCount;	myParamBlock.ioParam.ioBuffer = (char *)msgToSend;	PBWrite(&myParamBlock,true);	}void syncSendMidiEvent(short byteCount, unsigned char *msgToSend)	{	myParamBlock.ioParam.ioReqCount = byteCount;	myParamBlock.ioParam.ioBuffer = (char *)msgToSend;	PBWrite(&myParamBlock,false);	}	unsigned long Read4BytesBigEndian(const unsigned char *ptr) {unsigned long byte1 = ptr[0];unsigned long byte2 = ptr[1];unsigned long byte3 = ptr[2];unsigned long byte4 = ptr[3];// Shift bytes according to big endian formatreturn (byte1 << 24) | (byte2 << 16) | (byte3 << 8) | byte4;}unsigned long Read3BytesBigEndian(const unsigned char *ptr) {unsigned long byte1 = ptr[0];unsigned long byte2 = ptr[1];unsigned long byte3 = ptr[2];// Shift bytes according to big endian formatreturn (byte1 << 16) | (byte2 << 8) | byte3;}//read the next delta tick count for a given track, but also advance the trackParser by that amount of bytes needed to describe that deltaunsigned long readDelta(short track){long value = 0L;Byte temp;unsigned char *ptr;int bCount=1; //minimum count needed for describing the delta:1 . max=4;ptr = (unsigned char *)(*gMidiBuf) + trackStarters[track] + trackParsers[track]; //dereference the smf stashtemp = (Byte)*ptr;while(temp & 0x80) //must keep on reading after this one	{	bCount++;	temp &= 0x7F; //only get the lowest 7 bits	value+= (unsigned long)temp; //add it to the pile	value <<= 7; //shift the pile 7 spots to make room for next byte		ptr++; //go to next byte	temp = (Byte)*ptr; //fetch its value	}value += (unsigned long)temp; //final addition to close it offtrackParsers[track] += bCount; //advance the offset by the correct amount of bytes, get ready for the midi commandreturn value;}//set default values for the midi file recordvoid initSMF(){theOne.format = 0; //type 0, single tracktheOne.trackcount = 1; //goes with type 0theOne.tick = 48; //there are other defaults for ticks per quarter notestheOne.nn = 4;theOne.dd = 2; //4:4 time signaturetheOne.cc = 24;theOne.bb = 8;theOne.totalDuration = 0;theOne.uspqn = 500000; //settles only after at least one Meta Set Tempo, combined with the header's tick per quarter note//default is 500,000 microseconds per quarter notetheOne.uspt = theOne.uspqn / (unsigned long)theOne.tick;theOne.isPaused = true;}//checks the tempo, number of tracks, etcvoid readSMFHeader(int startIndex)	{	int i = startIndex;	unsigned char *ptr;		HLock((Handle)gMidiBuf);	ptr = (unsigned char *)(*gMidiBuf);		//skip inital header tag and size parameter, 4 bytes each	i+=8;		//read format type, 2 bytes	theOne.format = (unsigned int)(*(ptr+i+1))				   |(((unsigned int)(*(ptr+i  )))<<8);	i+=2;		//read trackcount, 2 bytes	theOne.trackcount = (unsigned int)(*(ptr+i+1))				       |(((unsigned int)(*(ptr+i  )))<<8);	i+=2;		//read ticks per quarter note, 2 bytes	theOne.tick =   (unsigned int)(*(ptr+i+1))				   |(((unsigned int)(*(ptr+i  )))<<8);	i+=2;			//printf("\ntick pqn=%d",theOne.tick);	HUnlock((Handle)gMidiBuf);	}//must be run after the header has been read and parsed, so we know the track countvoid allocateTracks(){int i;unsigned char *ptr;long cumul=18L; //index used to sniff start of each track. skip 14 byte header + first 4 byte tagif(trackStarters !=NULL) DisposPtr((Ptr)trackStarters);	//if(trackStarters !=NULL) free(trackStarters);//trackStarters = (unsigned long *)malloc(sizeof(unsigned char *) * theOne.trackcount);trackStarters = (unsigned long *)NewPtr(sizeof(unsigned char *) * theOne.trackcount);if(trackParsers !=NULL) DisposPtr((Ptr)trackParsers);//if(trackParsers !=NULL) free(trackParsers);//trackParsers = (unsigned long *)malloc(sizeof(unsigned char *) * theOne.trackcount);trackParsers = (unsigned long *)NewPtr(sizeof(unsigned char *) * theOne.trackcount);if(pendingDeltas !=NULL) DisposPtr((Ptr)pendingDeltas);//if(pendingDeltas !=NULL) free(pendingDeltas);//pendingDeltas = (unsigned long *)malloc(sizeof(unsigned long) * theOne.trackcount);pendingDeltas = (unsigned long *)NewPtr(sizeof(unsigned long) * theOne.trackcount);if(oldCmds !=NULL) DisposPtr((Ptr)oldCmds);//if(oldCmds !=NULL) free(oldCmds);//oldCmds = (unsigned char *)malloc(sizeof(unsigned char) * theOne.trackcount);oldCmds = (unsigned char *)NewPtr(sizeof(unsigned char) * theOne.trackcount);if(trackDone != NULL) DisposPtr((Ptr)trackDone);//if(trackDone != NULL) free(trackDone);//trackDone = (Boolean *)malloc(sizeof(Boolean) * theOne.trackcount);trackDone = (Boolean *)NewPtr(sizeof(Boolean) * theOne.trackcount);HLock((Handle)gMidiBuf);ptr = (unsigned char *)(*gMidiBuf);for(i = 0; i < theOne.trackcount; i++)	{	long byteCount = 0L;			trackParsers[i] = 0L; //initialize the offset within this track	trackDone[i] = false;	oldCmds[i] = 0x00;		byteCount =   Read4BytesBigEndian(ptr+cumul);    cumul+=4; //skip the 4 bytes used to stash the byte count    trackStarters[i]  = cumul; //initialize at the start of the data for this track	 	 //printf("\ntrack %d starts at %08lx", i, trackStarters[i]);      	cumul += byteCount + 4; //advance by that track's data bytes and the next track signature 'MTrk'.	}HUnlock((Handle)gMidiBuf);}//must be run after: header has been read, and allocateTracks has been done	//this must be used every time you need to reset the playback as wellvoid readyTracks(){int i;if(theOne.trackcount == 0 || trackParsers == NULL) return;for(i=0; i<theOne.trackcount; i++) 	{	trackParsers[i] = 0L;	trackDone[i] = false;	pendingDeltas[i]=0L;	oldCmds[i] = 0x00;	}	masterParser = 0L;	readyForNextNote=0;}unsigned long countTrackEvents(int whichTrack){unsigned long result = 0L;unsigned long curDelta;Boolean trackAtEnd; //loop exit for parsing a trackHLock((Handle)gMidiBuf);while(trackDone[whichTrack] == false){readDelta(whichTrack); //read it but throw out the resultif(isCommandRelevant(whichTrack,false)) result++; //just count, don't store, we don't have an allocated ram space for it yet}HUnlock((Handle)gMidiBuf);trackParsers[whichTrack]=0; //reset to start in case we wanted to do it again, or use the rt midi parsenplayreturn result;}void preProcessEvents(){int i; //loop indexunsigned int longI; //long loop indexBoolean huntingZeroes = true;unsigned long mostUrgentTimeFound; //lowest tick amount among the tracks searchedint mostUrgentIndex;unsigned long currentTimeFound;unsigned long usDelay; //for computing interrupt delays in usstruct mEvent *mPtr; //for dereferencingHLock((Handle)gMidiBuf);masterCount = 0L;//STEP 1//track count is known, but not how many events each. let's find outfor(i=0;i<theOne.trackcount;i++){readyTracks(); //reset parsers to startmasterCount += countTrackEvents(i);printf("\ntrack=%d count=%lu",i,masterCount);//pressSpacePause();}//STEP 2//allocate dynamic space to hold the events for each trackif(processedEvents != NULL)	{	if(HGetState((Handle)processedEvents) & 0x80)		HUnlock((Handle)processedEvents);	DisposHandle((Handle)processedEvents);	processedEvents = NULL;	}processedEvents = (Handle)NewHandle(sizeof(struct mEvent) * masterCount);masterParser = 0L;HLock((Handle)processedEvents);mPtr = (struct mEvent *)processedEvents;//parse and store events for each, only the ones that matter//initial pending time deltas readingreadyTracks(); //reset parsers to startfor(i=0; i<theOne.trackcount; i++)	{	if(trackDone[i] == true) continue; //this track is exhausted, go to next	pendingDeltas[i] = readDelta(i);	if(pendingDeltas[i]==0) huntingZeroes = true;	}tracksFinished = 0;while(tracksFinished < theOne.trackcount)	{	//exhaust all zero time delta pending events first	while(huntingZeroes)		{		huntingZeroes = false; //might be done after this pass		for(i=0; i<theOne.trackcount; i++)			{			if(trackDone[i]) continue;			if(pendingDeltas[i] == 0) 				{				//processMidiCommand(i);				if(isCommandRelevant(i,true)) //check if command is relevant and immediately store it					{ 					//printf("\ncmd track=%d tally=%08lx",i,absUs);										}				if(trackDone[i] == false) //only fetch a new thing if we are to keep going					{					pendingDeltas[i] = readDelta(i);			    	if(pendingDeltas[i]==0) huntingZeroes = true; //will have to deal with this with a full pass again			   		}				} //end of finding urgent events			}//end of checking all tracks		} //end of huntingZeroes			//find the lowest non-zero time delta pending event and do it	mostUrgentTimeFound = 0xFFFFFFFF;	mostUrgentIndex = 0;	/*	printf("\nshould be no zeroes");	for(i=0;i<theOne.trackcount;i++)printf("\ntr=%d pend=%08lx",i,pendingDeltas[i]);	*/	//if(pressSpacePause()) tracksFinished = theOne.trackcount; //force an exit			//For loop attempt to find the most pressing event with the lowest time delta to go	for(i=0; i<theOne.trackcount; i++)		{		if(trackDone[i] == true) continue; //this track is exhausted, go to next		if(pendingDeltas[i]==0) continue; //shouldn't happen but as a security				currentTimeFound = pendingDeltas[i];		if(currentTimeFound < mostUrgentTimeFound) 			{			mostUrgentTimeFound = currentTimeFound;			mostUrgentIndex = i; //new record in this track			}		}  //end of the for loop for most imminent event	if(mostUrgentTimeFound == 0xFFFFFFFF) break; //nothing found exit		//do the delay needed	if(mostUrgentTimeFound > 0) 		{		usDelay = theOne.uspt * mostUrgentTimeFound;				isCommandRelevant(mostUrgentIndex,true); //process it, advance the tick if relevant				if(trackDone[mostUrgentIndex] == false) 			{			pendingDeltas[mostUrgentIndex] = readDelta(mostUrgentIndex); //get the next one in line for the processed track			if(pendingDeltas[mostUrgentIndex]==0) huntingZeroes = true; //will have to deal with this with a full pass again			}			//remove that tick amount to other pending non-zero deltas		for(i=0; i<theOne.trackcount; i++)			{			if(trackDone[i]) continue; //don't update tracks that are done			if(i==mostUrgentIndex) continue; //don't deal with currently chosen track			if(pendingDeltas[i]==0) continue; //don't go negative for 0 valued deltas			pendingDeltas[i] -= mostUrgentTimeFound; //reduce every one else by this lowest champion			if(pendingDeltas[i]==0) huntingZeroes = true; //gonna mark this as being ASAP priority			} //end of remove ticks to other tracks		} //end of doing a delay when needed	}//end of tracksFinishedprintf("\n\nDONE preprocessing: %lu and the count was %lu",masterParser, masterCount);HUnlock((Handle)gMidiBuf);if(gMidiBuf != NULL) 	{	DisposHandle((Handle)gMidiBuf);	gMidiBuf = NULL;	}HUnlock((Handle)processedEvents);}void primeMidiFaster(){mEventPtr mPtr; //for dereferencingmasterParser = 0L; //reset to beginningif((HGetState((Handle)processedEvents) & 0x80) == 0) //is unlocked	HLock((Handle)processedEvents); //so lock itallNotesOff();mPtr = (mEventPtr)(*processedEvents);readyForNextNote = 0;PrimeTime((QElemPtr)&myTMInfo,-(long)mPtr->absT); //prime the first event}Boolean playmidi_faster(){mEventPtr mPtr; //for dereferencingunsigned int totalBytes = 0;unsigned int soFarBytes = 0;unsigned int nbComboEvents = 0;int i, j;unsigned long masterLeft;static unsigned char comboMsg[PBLOCKPOOL][256];unsigned long cumulative = 0L; //total time of bundled events if they are close enough to be treated as effectively simultaneousif(!readyForNextNote) return true;masterLeft = masterCount - masterParser;mPtr = (mEventPtr)(*processedEvents) + masterParser;	totalBytes = mPtr->byteCount; //start off with the event we need to donbComboEvents++; 	//count all the others that have 0 delay, we want to bunch them up together. first, count them/*//just check one event against FUDGETHRESHwhile((mPtr + nbComboEvents)->absT <= FUDGETHRESH && nbComboEvents < masterLeft) //check the next one	{	totalBytes += (mPtr+nbComboEvents)->byteCount;  	nbComboEvents++;  //add it to the pile	}*/	//check multiple events close together against FUDGETHRESH//FUDGETHRESH should be slightly less than the PBPool * 320 us.// ie if PBPool is 3, then FUDGETHRESH = 800-900 us is a good choicewhile(nbComboEvents < masterLeft)	{	cumulative += (mPtr + nbComboEvents)->absT;	if(cumulative > FUDGETHRESH) break;	totalBytes += (mPtr + nbComboEvents)->byteCount;	nbComboEvents++;	}		//prepare the space for the combined messagesfor(i=0; i<nbComboEvents; i++)	for(j=0; j < (mPtr+i)->byteCount; j++) 			comboMsg[pbPoolIdx][soFarBytes++] = (mPtr + i)->msg[j]; 			//send the amalgated message all in one gosendMidiEventRR(totalBytes, comboMsg[pbPoolIdx]);masterParser+=nbComboEvents; if(masterParser >= masterCount) return false;mPtr += nbComboEvents;readyForNextNote = 0;	PrimeTime((QElemPtr)&myTMInfo,-(long)mPtr->absT); //prime the next eventreturn true;}//tells you if you should count a single event while preprocessing a midi file//this assumes you checked the header and allocated space for the extern global arrays//this function will advance the needle ahead after an event is processed, in trackParsersBoolean isCommandRelevant(int whichTrack, Boolean wantStored){Boolean result = false; //assume it's not unless it isunsigned char midiCmd[6]; //6 bytes is the minimum we need for the commands we care aboutunsigned char *ptr;int isRunOn = 0; //check if it's a run-on, assume it's notint vlqLen = 1; //variable length quantity; track how bytes are needed in a given 0xFF meta eventlong vlq=0L; //the number itselfunsigned char *metaPtr; //look ahead for vlq situationsunsigned char lb; //lookout byte for vlqmEventPtr mEPtr; //dereference to parsed big structure	if(trackDone[whichTrack]) return false; //guard: no need to further analyze stuff ptr = (unsigned char *)(*gMidiBuf) + trackStarters[whichTrack] + trackParsers[whichTrack];//dereference the smf stashmEPtr = (mEventPtr)(*processedEvents) + masterParser;midiCmd[0] = *ptr;	if((midiCmd[0] & 0x80) == 0)		{		//run-on command		midiCmd[0] = oldCmds[whichTrack];		midiCmd[1] = *(ptr);		midiCmd[2] = *(ptr+1);		midiCmd[3] = *(ptr+2);		midiCmd[4] = *(ptr+3);		midiCmd[5] = *(ptr+4);		isRunOn=1;		}	else		{		midiCmd[1] = *(ptr+1);		midiCmd[2] = *(ptr+2);		midiCmd[3] = *(ptr+3);		midiCmd[4] = *(ptr+4);		midiCmd[5] = *(ptr+5);		}switch(midiCmd[0] & 0xF0) //check the status byte upper nybble		{		//2 byte commands		case 0xC0: //change program		case 0xD0: //channel pressure			result = true;			oldCmds[whichTrack] = midiCmd[0];					if(wantStored)				{				absUs = theOne.uspt * pendingDeltas[whichTrack]; //add the preconverted us to the tally				mEPtr->absT = absUs;				mEPtr->msg[0] = midiCmd[0];				mEPtr->msg[1] = midiCmd[1];				mEPtr->byteCount = 2;				masterParser++; //line up for next one				//printf("\nFound %02x %02x tr=%d at %08lx delt=%08lx",midiCmd[0],midiCmd[1], whichTrack,trackParsers[whichTrack], pendingDeltas[whichTrack]);				}			trackParsers[whichTrack] += 2 - isRunOn; //get ready for next delta			break;		//3 bytes commands		case 0x80: //note off		case 0x90: //note on		case 0xA0: //aftertouch		case 0xB0: //control change		case 0xE0: //pitch bend			result = true;			oldCmds[whichTrack] = midiCmd[0];			if(wantStored)				{				absUs = theOne.uspt * pendingDeltas[whichTrack]; //add the preconverted us to the tally				mEPtr->absT = absUs;				mEPtr->msg[0] = midiCmd[0];				mEPtr->msg[1] = midiCmd[1];				mEPtr->msg[2] = midiCmd[2];				mEPtr->byteCount = 3;				masterParser++; //line up for next one				//printf("\nFound %02x %02x tr=%d at %08lx delt=%08lx",midiCmd[0],midiCmd[1], whichTrack,trackParsers[whichTrack], pendingDeltas[whichTrack]);				}			trackParsers[whichTrack] += 3 - isRunOn; //get ready for next delta			break;		case 0xF0: //System messages, check for set tempo or for track end			oldCmds[whichTrack] = 0x00; //clear running status						if(midiCmd[0] == 0xFF) 				{											metaPtr = ptr +2; //skip 0xFF and type bytes				vlq = 0;				vlqLen = 0;				do{					lb = *metaPtr++;					vlq = (vlq << 7) | (lb & 0x7F); //push length 7 spots left and read the next					vlqLen++; //needed one more byte					if(vlqLen == 4) break; //max 4 bytes					} while(lb & 0x80);									if(midiCmd[1] == 0x2F) //Meta End of Track					{					trackDone[whichTrack] = true;					pendingDeltas[whichTrack] = 0;					tracksFinished++;					}				else if(midiCmd[1] == 0x51) //Meta set tempo event						{												theOne.uspqn = (((unsigned long)midiCmd[3])<< 16 )									| (((unsigned long)midiCmd[4])<< 8) 									| (unsigned long)midiCmd[5];						theOne.uspt = theOne.uspqn/(unsigned long)theOne.tick;						printf("\nPOST assign uspqn=%08lx 0=%02x 1=%02x 2=%02x",theOne.uspqn, midiCmd[3], midiCmd[4], midiCmd[5]);				//Delay(60,nil);						} //end set tempo event				if(trackDone[whichTrack] == false) trackParsers[whichTrack] += 2 + vlqLen + vlq; //get ready for next delta				}				break;		} //end of switchreturn result;}